        if lhs.saveSecretToKeychain != rhs.saveSecretToKeychain {
            return false
        }
        if lhs.mountOnLaunch != rhs.mountOnLaunch {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(name)
        hasher.combine(kind)
        hasher.combine(saveSecretToKeychain)
        hasher.combine(mountOnLaunch)
    }
}


