/**
 * Non-secret S3 connection config (mirrors `fskit_s3_backend::S3Config` minus the
 * `secret_access_key`, which never touches this struct or the config file).
 */
public struct S3Meta {
    public var bucket: String
    public var region: String
    /**
     * Custom endpoint for S3-compatible stores (MinIO, R2, RustFS). Empty ⇒ AWS.
     */
    public var endpoint: String
    public var accessKeyId: String
    public var sessionToken: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(bucket: String, region: String, 
        /**
         * Custom endpoint for S3-compatible stores (MinIO, R2, RustFS). Empty ⇒ AWS.
         */endpoint: String, accessKeyId: String, sessionToken: String?) {
        self.bucket = bucket
        self.region = region
        self.endpoint = endpoint
        self.accessKeyId = accessKeyId
        self.sessionToken = sessionToken
    }
}



extension S3Meta: Equatable, Hashable {
    public static func ==(lhs: S3Meta, rhs: S3Meta) -> Bool {
        if lhs.bucket != rhs.bucket {
            return false
        }
        if lhs.region != rhs.region {
            return false
        }
        if lhs.endpoint != rhs.endpoint {
            return false
        }
        if lhs.accessKeyId != rhs.accessKeyId {
            return false
        }
        if lhs.sessionToken != rhs.sessionToken {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(bucket)
        hasher.combine(region)
        hasher.combine(endpoint)
        hasher.combine(accessKeyId)
        hasher.combine(sessionToken)
    }
}


